class Solution {
public:
    string removeStars(string s) {
        int rem = 0;
        for(int i = s.size() - 1; i >= 0; i--){
            if(s[i] == '*'){
                rem++;
            } else if (rem > 0) {
                rem--;
            } else {
                continue;
            }
            s.erase(i, 1); 
        }
        return s;
    }
};
